SELECT 
FROM ai_prompt_templates

    del_flag = '0'
    AND name LIKE CONCAT('%', #{name}, '%')
    AND code LIKE CONCAT('%', #{code}, '%')
    AND scene = #{scene}
    AND platform_type = #{platformType}
    AND is_builtin = #{isBuiltin}
    AND status = #{status}

ORDER BY is_builtin DESC, id DESC

mapper.update:
UPDATE ai_prompt_templates
name = #{name}, code = #{code}, scene = #{scene}, system_prompt = #{systemPrompt}, user_prompt = #{userPrompt}, variables = #{variables}::jsonb, platform_type = #{platformType}, is_builtin = #{isBuiltin}, status = #{status}, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}

UPDATE ai_prompt_templates SET del_flag = '1', update_time = NOW()
WHERE id IN
#{id}
